const express = require('express');
const app = express();
const http = require('http');
const fs = require('fs');
const path = require('path');

app.use((req, res, next) => {
  const pluginConfigPath = process.env.PLUGIN_CONFIG_PATH || './plugins.json';
  const pluginConfig = JSON.parse(fs.readFileSync(pluginConfigPath, 'utf8'));

  pluginConfig.plugins.forEach(pluginName => {
    const pluginPath = path.join(__dirname, 'plugins', pluginName);
    const plugin = require(pluginPath);

    if (plugin.processRequest) {
      plugin.processRequest(req);
    }
  });

  next();
});

app.use((req, res, next) => {
  res.on('finish', () => {
    const pluginConfigPath = process.env.PLUGIN_CONFIG_PATH || './plugins.json';
    const pluginConfig = JSON.parse(fs.readFileSync(pluginConfigPath, 'utf8'));

    pluginConfig.plugins.forEach(pluginName => {
      const pluginPath = path.join(__dirname, 'plugins', pluginName);
      const plugin = require(pluginPath);

      if (plugin.processResponse) {
        plugin.processResponse(res);
      }
    });
  });

  next();
});

app.all('*', (req, res) => {
  const options = {
    hostname: 'localhost',
    port: 8000,
    path: req.url,
    method: req.method,
    headers: req.headers
  };

  const proxy = http.request(options, function (target_res) {
    res.writeHead(target_res.statusCode, target_res.headers);
    target_res.pipe(res, {
      end: true
    });
  });

  req.pipe(proxy, {
    end: true
  });
});

app.listen(3000, () => {
  console.log('API Gateway is running on port 3000');
});